import { useCallback, useEffect, useState } from 'react';
import {
  getDefaultVoucherListDateRange,
  MFE_LIST_FILTER_NS,
  readListFilterSession,
  type VoucherListFilterSession,
  writeListFilterSession,
} from '../utils/listFilterSession';
import { readListFilterAuthScopeFromStorage } from '../utils/listFilterAuthScope';

export function useVoucherListFilterState(listScope: string) {
  const [auth, setAuth] = useState(readListFilterAuthScopeFromStorage);
  const [initialized, setInitialized] = useState(false);

  useEffect(() => {
    const sync = () => setAuth(readListFilterAuthScopeFromStorage());
    window.addEventListener('storage', sync);
    window.addEventListener('linm:auth:logout', sync);
    return () => {
      window.removeEventListener('storage', sync);
      window.removeEventListener('linm:auth:logout', sync);
    };
  }, []);
  const [fromDate, setFromDate] = useState<string | undefined>();
  const [toDate, setToDate] = useState<string | undefined>();
  const [status, setStatus] = useState('');
  const [processingLevel, setProcessingLevel] = useState('');
  const [page, setPage] = useState(1);

  useEffect(() => {
    const saved = readListFilterSession<VoucherListFilterSession>(
      MFE_LIST_FILTER_NS,
      listScope,
      auth,
    );
    const initial = saved ?? {
      ...getDefaultVoucherListDateRange(),
      page: 1,
      status: '',
      processingLevel: '',
    };
    setFromDate(initial.fromDate);
    setToDate(initial.toDate);
    setStatus(initial.status ?? '');
    setProcessingLevel(initial.processingLevel ?? '');
    setPage(initial.page ?? 1);
    setInitialized(true);
  }, [listScope, auth]);

  useEffect(() => {
    if (!initialized) return;
    writeListFilterSession<VoucherListFilterSession>(MFE_LIST_FILTER_NS, listScope, auth, {
      fromDate,
      toDate,
      status: status || undefined,
      processingLevel: processingLevel || undefined,
      page,
    });
  }, [initialized, listScope, auth, fromDate, toDate, status, processingLevel, page]);

  const resetPage = useCallback(() => setPage(1), []);

  return {
    initialized,
    fromDate,
    setFromDate,
    toDate,
    setToDate,
    status,
    setStatus,
    processingLevel,
    setProcessingLevel,
    page,
    setPage,
    resetPage,
  };
}
